// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {

	// (POST /branches)
	ListBranches(ctx context.Context, request ListBranchesRequestObject) (ListBranchesResponseObject, error)

	// (POST /create-release)
	CreateRelease(ctx context.Context, request CreateReleaseRequestObject) (CreateReleaseResponseObject, error)

	// (POST /create-repo)
	CreateRepo(ctx context.Context, request CreateRepoRequestObject) (CreateRepoResponseObject, error)

	// (POST /create-tag)
	CreateTag(ctx context.Context, request CreateTagRequestObject) (CreateTagResponseObject, error)

	// (GET /healthz)
	Healthz(ctx context.Context, request HealthzRequestObject) (HealthzResponseObject, error)

	// (POST /parse-webhook)
	ParseWebhook(ctx context.Context, request ParseWebhookRequestObject) (ParseWebhookResponseObject, error)

	// (POST /pr-status)
	PrStatus(ctx context.Context, request PrStatusRequestObject) (PrStatusResponseObject, error)

	// (POST /register-webhook)
	RegisterWebhook(ctx context.Context, request RegisterWebhookRequestObject) (RegisterWebhookResponseObject, error)

	// (POST /repos)
	ListRepos(ctx context.Context, request ListReposRequestObject) (ListReposResponseObject, error)

	// (POST /sync)
	Sync(ctx context.Context, request SyncRequestObject) (SyncResponseObject, error)

	// (POST /upsert-pr)
	UpsertPr(ctx context.Context, request UpsertPrRequestObject) (UpsertPrResponseObject, error)

	// (POST /whoami)
	Whoami(ctx context.Context, request WhoamiRequestObject) (WhoamiResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// ListBranches operation middleware
func (sh *strictHandler) ListBranches(w http.ResponseWriter, r *http.Request) {
	var request ListBranchesRequestObject

	var body ListBranchesJSONRequestBody
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		sh.options.RequestErrorHandlerFunc(w, r, fmt.Errorf("can't decode JSON body: %w", err))
		return
	}
	request.Body = &body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.ListBranches(ctx, request.(ListBranchesRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "ListBranches")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(ListBranchesResponseObject); ok {
		if err := validResponse.VisitListBranchesResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

